<template>
  <div class="main-container">
    <h1 class="text-center text-primary main-title">Gestión de Lectores ProLectura</h1>
    
    <div class="dashboard-layout">
      
      <aside class="sidebar">
        <div class="card-container">
          <FormularioUsuarios @registro-exitoso="consultarUsuarios" />
        </div>
      </aside>

      <section class="content">
        <div class="card-container">
          <TablaUsuarios :lectores="usuarios" />
        </div>
      </section>

    </div>
  </div>
</template>

<script>
import FormularioUsuarios from '../components/FormularioUsuarios.vue'
import TablaUsuarios from '../components/TablaUsuarios.vue'

export default {
  name: 'UsuariosView',
  components: {
    FormularioUsuarios,
    TablaUsuarios
  },
  data() {
    return {
      usuarios: [] 
    }
  },
  methods: {
    async consultarUsuarios() {
      try {
        const respuesta = await fetch('https://mi-backend-railway-production.up.railway.app/api/usuarios');
        this.usuarios = await respuesta.json();
      } catch (error) {
        console.error("Error:", error);
      }
    }
  },
  mounted() {
    this.consultarUsuarios();
  }
}
</script>

