<template>
  <div class="form-container">
    <h2 class="form-header">Registro de Lectores</h2>
    <p class="form-subtitle">Administración de usuarios ProLectura</p>

    <form id="usuar-form" @submit.prevent="guardar" class="styled-form">
      <div class="form-body">
        <div class="form-group">
          <label for="id">ID de Registro</label>
          <input type="text" id="Id" v-model="id" placeholder="ID para consulta/borrado" />
        </div>

        <div class="form-group">
          <label for="nombre">Nombre</label>
          <input type="text" id="nombre" v-model="nombre" required placeholder="Nombre del lector" />
        </div>

        <div class="form-group">
          <label for="apellido">Apellido</label>
          <input type="text" id="apellido" v-model="apellido" required placeholder="Apellido del lector" />
        </div>

        <div class="form-group">
          <label for="identificacion">Identificación</label>
          <input type="number" id="identificacion" v-model="identificacion" required placeholder="N° Documento" />
        </div>
      </div>

      <div class="button-grid">
        <button type="submit" class="btn btn-save">Guardar</button>
        <button type="button" class="btn btn-update" @click="actualizar">Actualizar</button>
        <button type="button" class="btn btn-search" @click="consultar">Consultar</button>
        <button type="button" class="btn btn-delete" @click="eliminar">Eliminar</button>
      </div>
    </form>
  </div>
</template>

<script>
export default {
  name: 'FormularioUsuarios',
  data() {
    return {
      id: '',
      nombre: '',
      apellido: '',
      identificacion: ''
    }
  },
  methods: {
    async guardar() {
      const usuario = {
        nombre: this.nombre,
        apellido: this.apellido,
        identificacion: this.identificacion
      };
      try {
        const res = await fetch('https://mi-backend-railway-production.up.railway.app/api/usuarios', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(usuario)
        });
        if (res.ok) {
          alert("¡Lector guardado con éxito!");
          location.reload(); 
        }
      } catch (error) {
        console.error("Error al guardar:", error);
      }
    },
    async consultar() {
      if (!this.id) return alert("Ingresa un ID para consultar");
      try {
        const res = await fetch(`https://mi-backend-railway-production.up.railway.app/api/usuarios/${this.id}`);
        const data = await res.json();
        if (data) {
          this.nombre = data.nombre;
          this.apellido = data.apellido;
          this.identificacion = data.identificacion;
        }
      } catch (error) {
        alert("Lector no encontrado");
      }
    },
    async eliminar() {
      if (!this.id) return alert("Ingresa un ID para eliminar");
      if (!confirm("¿Seguro que deseas eliminar este registro?")) return;
      try {
        await fetch(`https://mi-backend-railway-production.up.railway.app/api/usuarios/${this.id}`, { method: 'DELETE' });
        alert("Registro eliminado");
        location.reload();
      } catch (error) {
        console.error("Error:", error);
      }
    },
    async actualizar() {
      if (!this.id) return alert("Ingresa el ID del lector a actualizar");
      const usuario = {
        nombre: this.nombre,
        apellido: this.apellido,
        identificacion: this.identificacion
      };
      try {
        await fetch(`https://mi-backend-railway-production.up.railway.app/api/usuarios/actualizar/${this.id}`, {
          method: 'PUT',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(usuario)
        });
        alert("Datos actualizados");
        location.reload();
      } catch (error) {
        console.error("Error:", error);
      }
    }
  }
}
</script>

